module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8
) (
    input wclk, rclk,
    input rst_n,
    input winc, rinc,
    input [WIDTH-1:0] wdata,
    output wfull, rempty,
    output [WIDTH-1:0] rdata
);

localparam ADDR_WIDTH = $clog2(DEPTH);

// Dual-port RAM instance
reg [WIDTH-1:0] ram [0:DEPTH-1];
reg [ADDR_WIDTH-1:0] waddr, raddr;

// Write port
always @(posedge wclk or negedge rst_n) begin
    if (!rst_n) begin
        waddr <= {ADDR_WIDTH{1'b0}};
    end else if (winc && !wfull) begin
        ram[waddr] <= wdata;
        waddr <= waddr + 1'b1;
    end
end

// Read port
always @(posedge rclk or negedge rst_n) begin
    if (!rst_n) begin
        raddr <= {ADDR_WIDTH{1'b0}};
    end else if (rinc && !rempty) begin
        raddr <= raddr + 1'b1;
    end
end

// Gray code conversion for pointers
function [ADDR_WIDTH-1:0] bin2gray(input [ADDR_WIDTH-1:0] bin);
    begin
        bin2gray = {bin[ADDR_WIDTH-1], bin[ADDR_WIDTH-2:0] ^ bin[ADDR_WIDTH-1:1]};
    end
endfunction

wire [ADDR_WIDTH-1:0] waddr_gray, raddr_gray;
assign waddr_gray = bin2gray(waddr);
assign raddr_gray = bin2gray(raddr);

// Full and empty flags
assign wfull = (waddr_gray == (raddr_gray ^ {1'b1, {(ADDR_WIDTH-1){1'b0}}}));
assign rempty = (waddr_gray == raddr_gray);

// Output data
assign rdata = ram[raddr];

endmodule
